     1→/**
     2→ * AI Routing Stage
     3→ *
     4→ * Stage 8 of the EmailCategorizer pipeline. Determines whether emails need AI classification
     5→ * based on confidence scores from multi-label selection. Routes high-confidence emails directly
     6→ * to final decision while sending uncertain cases through AI classification for enhancement.
     7→ *
     8→ * ROUTING DECISION LOGIC:
     9→ * - High Confidence (>=15): Skip AI - rule-based results are reliable
    10→ * - Medium Confidence (8-14): Route to AI - can benefit from enhanced classification
    11→ * - Very Low Confidence (<3): Skip AI - likely unclassifiable even with AI
    12→ * - No Labels Selected: Route to AI - last chance for classification
    13→ * - Hard Assertions: Skip AI - domain-based results are authoritative
    14→ */
    15→
    16→import { EmailMessage, ClassificationSession, SelectedLabel, CandidateScore } from '../types';
    17→
    18→// Interface for the classification input (internal stage API)
    19→export interface EmailClassification {
    20→  gmailId: string;
    21→  sessionId: string;
    22→  selectedLabels: SelectedLabel[];
    23→  candidateScores: Record<string, CandidateScore>;
    24→}
    25→
    26→// Configuration interface
    27→export interface AIRoutingConfig {
    28→  settings: {
    29→    ai_routing: {
    30→      high_confidence_threshold: number;
    31→      ai_required_threshold: number;
    32→      skip_ai_conditions: string[];
    33→    };
    34→  };
    35→  confidence_thresholds: {
    36→    high_confidence: number;
    37→    medium_confidence: number;
    38→    low_confidence: number;
    39→    ai_classification_required: number;
    40→  };
    41→}
    42→
    43→// Routing decision result
    44→export interface RoutingDecision {
    45→  route_to_ai: boolean;
    46→  routing_reason: string;
    47→  confidence_assessment: string;
    48→  cost_consideration: string;
    49→}
    50→
    51→// Simplified explainability trace for AI routing
    52→export interface AIRoutingExplainabilityTrace {
    53→  stage_type: string;
    54→  stage_order: number;
    55→  decision_factors: {
    56→    primary_score: number;
    57→    threshold_analysis: {
    58→      high_confidence_threshold: number;
    59→      ai_required_threshold: number;
    60→      low_confidence_threshold: number;
    61→      primary_score: number;
    62→      threshold_met: string;
    63→    };
    64→    competitor_analysis: {
    65→      close_competitors_found: boolean;
    66→      competitor_count: number;
    67→      multiple_labels_selected: boolean;
    68→    };
    69→  };
    70→  reasoning: string;
    71→  processing_metadata: {
    72→    processing_time_ms: number;
    73→    input_labels_count: number;
    74→    candidate_scores_count: number;
    75→  };
    76→}
    77→
    78→// Stage result interface
    79→export interface AIRoutingResult {
    80→  routing_decision: RoutingDecision;
    81→  routing_branch: 'ai_classification' | 'direct_to_merge';
    82→  explainability_trace: AIRoutingExplainabilityTrace;
    83→}
    84→
    85→/**
    86→ * AI Routing Stage Implementation
    87→ *
    88→ * Analyzes classification confidence and determines optimal routing strategy
    89→ * for email processing continuation.
    90→ */
    91→export function aiRoutingStage(
    92→  email: EmailMessage,
    93→  session: ClassificationSession,
    94→  classification: EmailClassification,
    95→  config: AIRoutingConfig
    96→): AIRoutingResult {
    97→  const startTime = Date.now();
    98→
    99→  // Validate inputs
   100→  validateInputs(email, session, classification, config);
   101→
   102→  // Extract routing thresholds with fallbacks
   103→  const highConfidenceThreshold =
   104→    config.settings.ai_routing.high_confidence_threshold || config.confidence_thresholds.high_confidence || 15;
   105→
   106→  const aiRequiredThreshold = config.confidence_thresholds.medium_confidence || 8;
   107→
   108→  const lowConfidenceThreshold = config.confidence_thresholds.low_confidence || 3;
   109→
   110→  const skipAiConditions = config.settings.ai_routing.skip_ai_conditions || [];
   111→
   112→  // Make routing decision
   113→  const routingDecision = makeRoutingDecision(
   114→    classification.selectedLabels,
   115→    classification.candidateScores,
   116→    highConfidenceThreshold,
   117→    aiRequiredThreshold,
   118→    lowConfidenceThreshold,
   119→    skipAiConditions
   120→  );
   121→
   122→  // Generate explainability trace
   123→  const explainabilityTrace = generateExplainabilityTrace(
   124→    classification,
   125→    routingDecision,
   126→    {
   127→      high_confidence_threshold: highConfidenceThreshold,
   128→      ai_required_threshold:
   129→        config.settings.ai_routing.ai_required_threshold ||
   130→        config.confidence_thresholds.ai_classification_required ||
   131→        12,
   132→      low_confidence_threshold: lowConfidenceThreshold,
   133→    },
   134→    startTime
   135→  );
   136→
   137→  return {
   138→    routing_decision: routingDecision,
   139→    routing_branch: routingDecision.route_to_ai ? 'ai_classification' : 'direct_to_merge',
   140→    explainability_trace: explainabilityTrace,
   141→  };
   142→}
   143→
   144→/**
   145→ * Validate input parameters
   146→ */
   147→function validateInputs(
   148→  email: EmailMessage,
   149→  session: ClassificationSession,
   150→  classification: EmailClassification,
   151→  config: AIRoutingConfig
   152→): void {
   153→  if (!email?.id && !(email as unknown as { gmailId?: string }).gmailId) {
   154→    throw new Error('Invalid email: id or gmailId is required');
   155→  }
   156→
   157→  if (!session?.id && !(session as unknown as { sessionId?: string }).sessionId) {
   158→    throw new Error('Invalid session: id or sessionId is required');
   159→  }
   160→
   161→  if (!classification) {
   162→    throw new Error('Classification is required');
   163→  }
   164→
   165→  if (!config) {
   166→    throw new Error('Configuration is required');
   167→  }
   168→
   169→  // Validate confidence scores
   170→  if (classification.selectedLabels) {
   171→    for (const label of classification.selectedLabels) {
   172→      if (isNaN(label.confidence) || !isFinite(label.confidence)) {
   173→        throw new Error('Invalid confidence score');
   174→      }
   175→    }
   176→  }
   177→}
   178→
   179→/**
   180→ * Core routing decision logic
   181→ */
   182→function makeRoutingDecision(
   183→  selectedLabels: SelectedLabel[],
   184→  candidateScores: Record<string, CandidateScore>,
   185→  highConfidenceThreshold: number,
   186→  aiRequiredThreshold: number,
   187→  lowConfidenceThreshold: number,
   188→  skipAiConditions: string[]
   189→): RoutingDecision {
   190→  // Case 1: No labels selected - route to AI for last chance classification
   191→  if (selectedLabels.length === 0) {
   192→    return {
   193→      route_to_ai: true,
   194→      routing_reason: 'No labels selected - AI classification may recover classification',
   195→      confidence_assessment: 'no_classification',
   196→      cost_consideration: 'recovery_attempt',
   197→    };
   198→  }
   199→
   200→  // Case 2: Check for hard assertions (skip AI condition)
   201→  if (skipAiConditions.includes('hard_assertion')) {
   202→    const hasHardAssertion = Object.values(candidateScores).some((score) => score.hardAssertion);
   203→    if (hasHardAssertion) {
   204→      return {
   205→        route_to_ai: false,
   206→        routing_reason: 'hard assertion applied - domain-based classification is authoritative',
   207→        confidence_assessment: 'hard_assertion_skip',
   208→        cost_consideration: 'ai_unnecessary',
   209→      };
   210→    }
   211→  }
   212→
   213→  // Case 3: Check primary label confidence
   214→  const primaryLabel = selectedLabels.find((label) => label.isPrimary) || selectedLabels[0];
   215→  const primaryScore = primaryLabel.confidence;
   216→
   217→  // High confidence - skip AI (rule-based results are reliable)
   218→  if (primaryScore >= highConfidenceThreshold) {
   219→    return {
   220→      route_to_ai: false,
   221→      routing_reason: `High confidence primary label ${primaryLabel.category} (score: ${primaryScore}) - rule-based results reliable`,
   222→      confidence_assessment: 'high_confidence',
   223→      cost_consideration: 'ai_unnecessary',
   224→    };
   225→  }
   226→
   227→  // Very low confidence - skip AI (likely unclassifiable)
   228→  if (primaryScore < lowConfidenceThreshold) {
   229→    return {
   230→      route_to_ai: false,
   231→      routing_reason: `Very low confidence primary label ${primaryLabel.category} (score: ${primaryScore}) - likely unclassifiable`,
   232→      confidence_assessment: 'very_low_confidence',
   233→      cost_consideration: 'ai_ineffective',
   234→    };
   235→  }
   236→
   237→  // Medium confidence range - analyze further for AI routing decision
   238→  const hasMultipleLabels = selectedLabels.length > 1;
   239→  const hasCloseCompetitors = checkCloseCompetitors(candidateScores, primaryScore, 3);
   240→
   241→  // Route to AI if in uncertain range and conditions suggest AI could help
   242→  if (primaryScore >= lowConfidenceThreshold && primaryScore < highConfidenceThreshold) {
   243→    let aiRoutingReason = `Medium confidence primary label ${primaryLabel.category} (score: ${primaryScore})`;
   244→    let costConsideration = 'beneficial_enhancement';
   245→
   246→    // Additional factors for AI routing decision (prioritize multiple labels over close competitors)
   247→    if (hasCloseCompetitors) {
   248→      aiRoutingReason += ' with close competing categories';
   249→      costConsideration = 'disambiguation_valuable';
   250→    }
   251→
   252→    if (hasMultipleLabels) {
   253→      aiRoutingReason += ' with multiple labels selected';
   254→      costConsideration = 'multi_label_validation';
   255→    }
   256→
   257→    // Conservative approach: medium confidence usually benefits from AI
   258→    if (primaryScore >= aiRequiredThreshold) {
   259→      return {
   260→        route_to_ai: true,
   261→        routing_reason: aiRoutingReason + ' - AI classification can improve accuracy',
   262→        confidence_assessment: 'medium_confidence',
   263→        cost_consideration: costConsideration,
   264→      };
   265→    } else {
   266→      return {
   267→        route_to_ai: false,
   268→        routing_reason: aiRoutingReason + ' but below AI routing threshold - accept rule-based result',
   269→        confidence_assessment: 'low_medium_confidence',
   270→        cost_consideration: 'cost_threshold_not_met',
   271→      };
   272→    }
   273→  }
   274→
   275→  // Default case (shouldn't reach here with proper thresholds)
   276→  return {
   277→    route_to_ai: false,
   278→    routing_reason: `Unclear confidence assessment (score: ${primaryScore}) - defaulting to rule-based results`,
   279→    confidence_assessment: 'unclear',
   280→    cost_consideration: 'default_conservative',
   281→  };
   282→}
   283→
   284→/**
   285→ * Check if there are close competing categories that AI could help disambiguate
   286→ */
   287→function checkCloseCompetitors(
   288→  candidateScores: Record<string, CandidateScore>,
   289→  primaryScore: number,
   290→  competitorGap: number = 3
   291→): boolean {
